var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"수습 요원 자격을 만족했군요. 축하합니다. 로이 버넷.","JPN":"インターン・エージェントとしての資格を満たしました。\\nおめでとうございます、ロイ・バーネット。","ENG":"So you've met the prerequisites to become a probationary agent. Congratulations. Roy Burnett.","TWN":"你達到實習特工資格了，恭喜你，羅伊·伯內特。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"애송이 티를 벗으려면 아직 갈 길이 멀지만 말이야.","JPN":"一人前になるまで、まだ先は長いけどな。","ENG":"The lad's still got long ways to go till he stops smelling like an FNG.","TWN":"不過要褪去這一身乳臭味，還差得遠呢。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헹. 양로원에 들어갈 때도 그런 소리가 나오나 보자고, 할배.","JPN":"へッ。介護施設に入る時は、そんなこと言ってられなくなるぜ、ジジイ？","ENG":"Heh. Let's see if you'll still be running your mouth like that when you're in a rest home, old chap.","TWN":"哼，等你進養老院時，看你還能不能說出這種話，老頭。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 마음 편히 일 맡기고 은퇴할 수 있다면 나야 환영이지.","JPN":"はは。安心して仕事を任せて引退できるなら、俺は大歓迎だ。","ENG":"Hah hah, I'd welcome the day I can retire in peace in a heartbeat. So long as I know I can count on you.","TWN":"哈哈，要是能放心地把工作交給你然後隱退，我當然樂意了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 갑작스럽겠지만, 다음 임무입니다.","JPN":"それでは、急ですが次の任務です。","ENG":"I hate interrupting this merry banter, but I must brief the young agent on his next mission.","TWN":"那個不好意思，下個任務來了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔데? 홍차 폭탄한테 시달리는 일만 아니면 까짓 거 뭐라도 상관없어.","JPN":"何だ？　紅茶爆弾に叩きのめされること以外なら、何だって構わないぜ。","ENG":"What is it? I'm up for anything as long as I don't have to deal with the Tea Bomb.","TWN":"是什麼？只要不是被紅茶炸彈折磨，什麼工作我都願意接。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 오랜 적수와의 전면전에 대비해 믿을 만한 협력자를 찾고 있습니다.","JPN":"本機関は敵との全面戦に備えて、信頼できる協力者を探しています。","ENG":"The Institution is seeking a reliable partner to prepare for an all-out war against a long-standing enemy.","TWN":"為了應對與老對頭的全面戰爭，正在尋找可靠的合作者。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"실력은 뛰어나면서, 대외적으로는 아직 부각되지 않은 조직이라면 더욱 좋죠.","JPN":"腕が立つと同時に対外的にはまだ知られていない組織なら、なお良いですね。","ENG":"Ideally, it would be another organization that is capable, yet relatively obscure.","TWN":"最好是實力出眾，而且還不為世人所知曉的組織。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 원, 할배 농담도 할 줄 알았어?","JPN":"ジジイ、冗談がうまいな。","ENG":"Well, old chap. I never took you for someone with a sense of humour!","TWN":"真是的，老頭也會開玩笑了？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 입맛에 딱 들어맞는 데가 퍽이나 있겠다.","JPN":"そんな条件にピッタリはまる組織なんてあるわけないだろ。","ENG":"Good luck trying to find a team like that in this lifetime.","TWN":"哪有這麼稱心如意的事情。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아뇨. 있습니다. 아가씨께서 직접 추천해 주시더군요.","JPN":"いいえ、あります。お嬢様が直々に推薦されました。","ENG":"No need for such luck. As a matter of fact, we've already found one. Lady Elizabeth made the recommendation herself.","TWN":"不，有。是小姐親自推薦的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......엥?","JPN":"……えっ？","ENG":"Huh?","TWN":"……哼？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하핫. 코핀 컴퍼니라는 곳일세.","JPN":"ははっ。コフィンカンパニーというところだ。","ENG":"Hah hah! They call themselves the Coffin Company.","TWN":"哈哈，是一個叫科芬的公司。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋은 경험이 될 거야. 위장 신분을 하나 준비해 뒀으니 다녀와 보게.","JPN":"いい経験になるだろう。偽装する身分を用意しておいたから、行ってくるといい。","ENG":"I'm sure it'll be a great experience. We've prepared a cover identity for you. Off you go then.","TWN":"這是一個很好的機會，我們給你安排了一個假身份，你去吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 마침 잘 만났군!","JPN":"お、ちょうどいいところに！","ENG":"Oh, just the man I was looking for!","TWN":"喔，正好要找你！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그러니까...... 사장님이었지?","JPN":"ああそうだ……社長だったか？","ENG":"Erm... Boss, right?","TWN":"啊，你是……老闆吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하핫, 입사한 지도 꽤 됐는데 이제 알아볼 때도 되지 않았나?","JPN":"はははっ。入社してかなり経つから、そろそろ見慣れてほしいな。","ENG":"Hah hah. Isn't it about time you recognized me? It's been a while since you've joined our company, after all.","TWN":"哈哈哈，你進公司也很長一段時間了，也該記住我了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"로봇 사장님을 아무렇지 않게 받아들이는 녀석들이 이상한 거 아냐?","JPN":"ロボットの社長を普通に受け入れる方がおかしいだろ？","ENG":"Well, I'm still surprised that people here are taking a robot boss for granted.","TWN":"理所當然地接受機器人是老闆，這才奇怪吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론 그랬지. 하지만 지금은 모든 사원들이 나의 뛰어난 영도력을 받아들일 준비가 되었다네.","JPN":"もちろん、初めは怪しまれた。\\nしかし、今は全社員が私の素晴らしいリーダーシップを受け入れている。","ENG":"Well, they were like you at first. But now every employee is ready to fully embrace my great leadership.","TWN":"的確如此。不過現在所有員工都已經認同我出色的領導能力了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네도 머지않아 그렇게 되길 기대하지.","JPN":"君も近々そうなる日が来るだろう。","ENG":"I hope you'll soon join their ranks.","TWN":"希望不久的將來，你也會這樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇지, 부사장에게 자네 얘기를 들었다네!","JPN":"そうだ、副社長から君の話を聞いたのだ！","ENG":"By the way, the Vice President told me a lot about you!","TWN":"對了，我聽副總提起你的事了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네가 우리 회사에 입사한 뒤로 사내 위생 수준이 두 단계는 올라갔다고 하더군.","JPN":"君が我が社へ入社してから、社内の衛生レベルが2段階は上がったと言っていた。","ENG":"She said the company's level of sanitation has significantly increased ever since you joined us.","TWN":"聽說自從你進公司後，公司內部的衛生水準提高了兩個等級。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"먹다 남긴 컵라면 용기가 사라진 쾌적한 직원 휴게실!","JPN":"食べ残したカップ麺が消えた、快適な職員休憩室！","ENG":"No more leftover sandwiches collecting mold in the break room!","TWN":"員工休息室裡亂放的泡麵垃圾不見了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"클로에 양이 찍어내는 사이비 부적들을 모두 없애버린 정돈된 작전실!","JPN":"クロエ君が勝手に貼ったオカルト護符を全て取り払った、きれいな作戦室！","ENG":"No more shady talismans and tarot cards from Chloe cluttering up the ops room!","TWN":"作戰室裡克洛伊小姐印的假符咒也被清理掉了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CLAP_02"},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"먼지 한 톨 찾아보기 힘든 탁 트인 복도까지!","JPN":"ほこりすら目につかない、広々とした廊下！","ENG":"And there's not a speck of dust to be found in the hallway now!","TWN":"還有走廊，一塵不染且十分通暢！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네는 정말 우리 회사의 보배일세.","JPN":"君は我が社の宝だ。","ENG":"You are truly an asset to our company.","TWN":"你真是我們公司的寶物啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"흥. 난 그냥 눈에 거슬리는 것들은 내 앞에서 치워야 직성이 풀릴 뿐이야.","JPN":"ふん。俺はただ、目障りなものを片付けなきゃ気が済まないだけだ。","ENG":"Hmpf. I just have no patience for things that bother me, that's all. I've got to clean them right up.","TWN":"哼，我只是無法忍受那些礙眼的東西出現在眼前，所以才清理掉的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"적이나 잡동사니나 그게 그거 아니겠어.","JPN":"敵もゴミも一緒だろ？","ENG":"Whether it's the enemy or trash, same difference.","TWN":"不管是敵人還是雜物，都差不多嘛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"역시 예상했던 대로군! 자네는 환경 미화에 천부적인 재능이 있어!","JPN":"やはり私の予想どおりだ！　君には環境美化における、天賦の才がある！","ENG":"Just as I thought! You've got a knack for the janitorial line of work!","TWN":"果然跟我預料得一樣！你在美化環境方面很有天賦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그, 그래? 그런 얘기는 처음 듣는데?","JPN":"そ、そうか？　そんな話は初めて聞いたぜ？","ENG":"R-really? No one's told me that before.","TWN":"是、是嗎？這還是第一次有人這樣說我？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어허, 주변 사람들이 보는 눈이 없나 보군.","JPN":"君の周りの人たちは見る目がない。","ENG":"Oh my, it seems that those around you never had an eye for true talent.","TWN":"呵呵，看來是你周圍的人真是沒眼光啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네만 괜찮다면 당장 종신 고용을 제의할 생각이 있네.","JPN":"君さえよければ、今すぐにでも終身雇用を提案したい。","ENG":"If you don't mind, I'd like to offer you a lifetime employment contract.","TWN":"只要你願意，我想馬上終身雇傭你。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"앞으로 영원히 실직 걱정 없이 우리 회사에서 안정적인 직장 생활을 영위하는 건 어떻겠나?","JPN":"この先ずっと何の心配もなく、我が社で安定的に働くのはどうだ？","ENG":"How would you like to spend the rest of your life working for this company without ever having to worry about job security?","TWN":"這樣你就有了一份穩定的工作，永遠不用擔心失業了，你覺得怎麼樣？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......그래서 잠입 사흘 만에 전향 당할 뻔 했다는 말이로군요.","JPN":"……それで潜入4日目にして、転向しかけたということですか。","ENG":"So, that's how you nearly defected to the other side within three days of going undercover.","TWN":"……所以，你在潛入第三天就差點變節了，是吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"본인이 생각해도 너무 지조가 없다는 생각이 들지 않나요, 물벼룩.","JPN":"自分で考えても、節操がなさすぎると思いませんか、ミジンコ？","ENG":"I thought even you'd have more integrity than that, Water Flea.","TWN":"你也覺得自己很沒忠誠吧，水蚤。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"누가 전향했대?! 그냥 생각만 해 본 거야, 생각만!","JPN":"転向してない！　ただちょっと、考えただけだ！","ENG":"Who ever said anything about defecting? I was just toying with the idea, that's all!","TWN":"誰說我變節了？！我就是想想而已，想想！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제안해 준 사장님 성의를 봐서...... 그게 사람 사는 예의라는 거잖아?","JPN":"提案してくれた社長の誠意は無視できないしな……それが礼儀ってもんだろ？","ENG":"I mean, the bloke was offering me a pretty good deal... The polite thing to do is at least consider the idea, you know?","TWN":"看在提議的老闆這麼有誠意的份上……那是做人該有的禮儀不是嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아무데나 예의라는 말을 갖다 붙이는군요. 그래서 당신이 물벼룩이라는 거에요.","JPN":"適当に礼儀と言っておけばどうにかなると思っているところが、本当にミジンコらしいですね。","ENG":"You seem to have such a casual notion of the concept of politeness. That's why you're nothing but a Water Flea.","TWN":"真是什麼事都能扯到禮儀上，所以才說你是水蚤。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야! 그 놈의 물벼룩 소리 좀 그만해!","JPN":"おい！　いい加減、ミジンコって呼ぶな！","ENG":"Come on! Stop calling me that!","TWN":"喂！妳別再說那該死的水蚤了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"싫어요.","JPN":"お断りしますわ。","ENG":"Nope.","TWN":"我偏不要。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩. 물벼룩. 물벼룩. 물벼룩. 물벼룩. 물벼룩. 물벼룩. 물벼룩.","JPN":"ミジンコ。ミジンコ。ミジンコ。ミジンコ。ミジンコ。\\nミジンコ。ミジンコ。ミジンコ。","ENG":"Water Flea. Water Flea. Water Flea. Water Flea. Water Flea. Water Flea. Water Flea. Water Flea.","TWN":"水蚤、水蚤、水蚤、水蚤、水蚤、水蚤、水蚤、水蚤。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어쨌든 이렇게 연락한 걸 보면 최소한의 첩보 활동은 했다는 뜻이겠죠.","JPN":"とりあえず、こうして連絡しているということは、最低限の密偵活動はしたということでしょう。","ENG":"In any case, I presume you've been able to conduct minimal espionage at the very least, seeing as you've decided to get in touch.","TWN":"不管怎樣，既然你聯絡我了，就代表你至少做了間諜活動。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"조사한 내용을 보고해 보시죠.","JPN":"調査内容を報告してください。","ENG":"Go ahead and brief me on whatever you've found.","TWN":"報告一下你的調查結果吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 뭐...... 이것 저것 알아보긴 했는데 집사 할배 말이랑 다르게 딱히 그럴싸한 걸 별로 없던걸?","JPN":"いや、まあ……色々調べたけど、執事のジジイが話してたのと違って、\\n以外と普通だったぜ？","ENG":"Well... I looked into a bunch of things, but I didn't find anything extraordinary like your butler suggested.","TWN":"那個……我到處打聽過了，但跟管家爺爺說的不一樣，好像沒什麼特別的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그냥 좀 별난 녀석들이 많은 거 정도?","JPN":"あえて言うなら、ちょっと変わったやつらが多いってくらいかな？","ENG":"They just have a few more quirky individuals than usual, I guess?","TWN":"就是有很多奇怪的傢伙？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 그건 우리도 마찬가지잖아. 뭐 그렇게 특이할 건 없다고 보는데.","JPN":"でも、それはうちも一緒だろ？　だから、特に何もないかな。","ENG":"But the same goes for us, really. So I don't think there's anything particularly unusual about them.","TWN":"不過這一點我們也一樣啊，沒看出來有什麼特別的地方。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......하아, 알겠어요.","JPN":"……はあ、わかりました。","ENG":"*Sigh* Very well.","TWN":"……哈啊，知道了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저도 쉽게 알아낼 거라고 생각하진 않았습니다. 좀 더 노력해 주세요.","JPN":"あなたがすぐに情報を入手するとは思っていませんでした。\\nもう少し努力してください。","ENG":"I didn't expect this to be easy anyway. Please do try harder.","TWN":"我也沒想過能這麼輕易就查出來，你就再努力一點吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다음 보고 때는 더 나은 결과를 기대하도록 하죠.","JPN":"次回の報告では、より良い結果を期待してますわ。","ENG":"I hope to see some improvement in your next briefing.","TWN":"希望下次報告時，能有更好的結果。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알았어.","JPN":"わぁったよ。","ENG":"Fine.","TWN":"知道了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 지금 통신, 보안은 제대로 확인한 거겠죠?","JPN":"ところで今の通信、セキュリティはちゃんと確認しましたか？","ENG":"By the way, did you make sure this call is secure?","TWN":"不過現在的通信安全，你都仔細檢查過了吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헹. 당연하지. 그런 것도 못할 줄 아냐.","JPN":"へッ。もちろんだ。それくらいは俺にだってできる。","ENG":"Heh. Of course. Did you really think I'd be that incompetent?","TWN":"哼，當然了。妳也太小看我了吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......못하는군요.","JPN":"……できてませんね。","ENG":"Looks like he is that incompetent.","TWN":"……原來真的不行啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그래서 이제 어떻게 하실 생각이죠?","JPN":"それで、どうなさいますか？","ENG":"So what now?","TWN":"所以，現在您打算怎麼辦？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기관의 새 주인께서 아주 귀여운 짓을 하는군. 마음에 들어.","JPN":"機関の新しい主が、かわいらしいことをしてくれたな。気に入った。","ENG":"Aww... The new master of the Institution thinks she's being so clever. I think I like her already.","TWN":"機關的新主人還真可愛，我喜歡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"당분간은 모른 척 해 주게. 덕분에 돈 주고도 찾지 못할 S급 청소요원이 생기지 않았나.","JPN":"当分の間は目をつぶってやろう。\\nおかげで金を積んでもスカウトできない、S級の掃除エージェントが手に入っただろ？","ENG":"Just pretend like you don't know anything for now. Thanks to them, we've got ourselves the Grade S cleaning agent we could ask for.","TWN":"暫時就先裝作不知道吧。多虧了他，我們才有了花錢都請不到的S級清潔特工不是嗎。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"저 친구가 없던 시절로 다시 돌아갈 수 있을지 난 도저히 자신이 없군.","JPN":"私はロイ君がいなかった頃に戻れる気がしない。","ENG":"I honestly can't picture the company without him anymore.","TWN":"我實在不想回到沒有他的日子了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"알겠습니다. 김하나 부장에게도 그렇게 전해 두도록 하죠.","JPN":"承知しました。ナカシマ・スズカ部長にも、そう伝えておきます。","ENG":"Understood. I'll make sure Hana is tracking that as well.","TWN":"知道了。我會如實轉告金荷娜部長的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};